#include "Stats.h"
#include "MathUtils.h"
uint8_t Stats::readiness(const SessionResult&r)const{if(!baseline.quickSamples)return 0;float rt=baseline.quickMedian/(r.median?r.median:1)*40,cs=baseline.quickSpread/(r.spread+1)*25,lp=(1.f-r.lapses/10.f)*20,fs=(1.f-r.falseStarts/10.f)*10,ac=r.attempts?((float)r.correct/r.attempts)*5:5;return MathUtils::clampScore(rt+cs+lp+fs+ac);}
void Stats::recordQuick(const SessionResult&r){last=r;sessions++;if(r.median>0){if(!personalBest||r.median<personalBest)personalBest=r.median;if(baseline.quickSamples<5){float n=baseline.quickSamples;baseline.quickMedian=(baseline.quickMedian*n+r.median)/(n+1);baseline.quickSpread=(baseline.quickSpread*n+r.spread)/(n+1);baseline.quickLapseRate=(baseline.quickLapseRate*n+r.lapses/10.f)/(n+1);baseline.quickSamples++;}else{baseline.quickMedian=MathUtils::ema(baseline.quickMedian,r.median,.10f);baseline.quickSpread=MathUtils::ema(baseline.quickSpread,r.spread,.10f);baseline.quickLapseRate=MathUtils::ema(baseline.quickLapseRate,r.lapses/10.f,.10f);}}scores[scoreCount++%10]=r.score;}
void Stats::recordFocus(const SessionResult&r){last=r;sessions++;if(r.median>0){baseline.focusMedian=baseline.focusMedian?MathUtils::ema(baseline.focusMedian,r.median,.15f):r.median;baseline.focusLapseRate=MathUtils::ema(baseline.focusLapseRate,r.lapses/10.f,.15f);}scores[scoreCount++%10]=r.score;}
void Stats::recordChoice(const SessionResult&r){last=r;sessions++;scores[scoreCount++%10]=r.score;}
void Stats::recordRhythm(const SessionResult&r){last=r;sessions++;if(r.correct>0)baseline.rhythmError=baseline.rhythmError?MathUtils::ema(baseline.rhythmError,abs(r.bias),.15f):abs(r.bias);scores[scoreCount++%10]=r.score;}
void Stats::recordMemory(const SessionResult&r){last=r;sessions++;if(r.bias>memoryBest)memoryBest=r.bias;scores[scoreCount++%10]=r.score;}
